beforeAll(async () => {
      getMetadataStorage().clear();

      @InputType()
      class DateInput {
        @Field(type => Date)
        date: any;

        @Field(type => Date, { nullable: true })
        nullableDate?: any;
      }

      @Resolver()
      class SampleResolver {
        @Query(returns => Date)
        returnDate(): any {
          return new Date();
        }

        @Query(returns => Date, { nullable: true })
        nullableReturnDate(): Date | null {
          return null;
        }

        @Query(returns => Date)
        returnStringAsDate(): any {
          return new Date().toISOString();
        }

        @Query()
        argDate(@Arg("date", type => Date) date: any): boolean {
          localArgDate = date;
          return true;
        }

        @Query()
        nullableArgDate(
          @Arg("date", type => Date, { nullable: true })
          date: any,
        ): boolean {
          localArgDate = date;
          return true;
        }

        @Query()
        inputDate(@Arg("input", type => DateInput) dateInput: any): boolean {
          localArgDate = dateInput.date;
          return true;
        }
      }

      sampleResolver = SampleResolver;
    })

